function createUtilityOverlayActionHandler(actions) {
  return (ctx, target, event) => {
    for (const action of actions) {
      const matched = target?.closest?.(action.selector);
      if (!matched) {
        continue;
      }
      action.run(ctx, matched, event);
      return true;
    }
    return false;
  };
}

